     1|const express = require('express');
     2|const cors = require('cors');
     3|const axios = require('axios');
     4|
     5|const app = express();
     6|const PORT = 3001;
     7|
     8|// 心知天气 API 配置
     9|const API_KEY = 'SgajT9lBa9yQG2Ef_';
    10|const API_BASE_URL = 'https://api.seniverse.com/v3/weather';
    11|
    12|// 中间件
    13|app.use(cors());
    14|app.use(express.json());
    15|
    16|/**
    17| * GET /api/weather/now
    18| * 查询实时天气
    19| * Query params: location (城市名, 如 beijing)
    20| */
    21|app.get('/api/weather/now', async (req, res) => {
    22|  try {
    23|    const { location } = req.query;
    24|    if (!location) {
    25|      return res.status(400).json({ error: '请提供 location 参数' });
    26|    }
    27|
    28|    const response = await axios.get(`${API_BASE_URL}/now.json`, {
    29|      params: {
    30|        key: API_KEY,
    31|        location,
    32|        language: 'zh-Hans',
    33|        unit: 'c'
    34|      }
    35|    });
    36|
    37|    res.json(response.data);
    38|  } catch (error) {
    39|    console.error('获取实时天气失败:', error.message);
    40|    if (error.response) {
    41|      res.status(error.response.status).json({
    42|        error: '获取天气数据失败',
    43|        detail: error.response.data
    44|      });
    45|    } else {
    46|      res.status(500).json({ error: '服务器内部错误' });
    47|    }
    48|  }
    49|});
    50|
    51|/**
    52| * GET /api/weather/daily
    53| * 查询未来天气预报
    54| * Query params: location (城市名), days (天数, 默认5)
    55| */
    56|app.get('/api/weather/daily', async (req, res) => {
    57|  try {
    58|    const { location, days = 5 } = req.query;
    59|    if (!location) {
    60|      return res.status(400).json({ error: '请提供 location 参数' });
    61|    }
    62|
    63|    const response = await axios.get(`${API_BASE_URL}/daily.json`, {
    64|      params: {
    65|        key: API_KEY,
    66|        location,
    67|        language: 'zh-Hans',
    68|        unit: 'c',
    69|        start: 0,
    70|        days: Math.min(parseInt(days) || 5, 15)
    71|      }
    72|    });
    73|
    74|    res.json(response.data);
    75|  } catch (error) {
    76|    console.error('获取天气预报失败:', error.message);
    77|    if (error.response) {
    78|      res.status(error.response.status).json({
    79|        error: '获取天气预报数据失败',
    80|        detail: error.response.data
    81|      });
    82|    } else {
    83|      res.status(500).json({ error: '服务器内部错误' });
    84|    }
    85|  }
    86|});
    87|
    88|// 启动服务器
    89|app.listen(PORT, () => {
    90|  console.log(`🌤️  天气查询后端服务已启动: http://localhost:${PORT}`);
    91|  console.log(`📡 实时天气: http://localhost:${PORT}/api/weather/now?location=beijing`);
    92|  console.log(`📡 天气预报: http://localhost:${PORT}/api/weather/daily?location=beijing&days=5`);
    93|});

